#include <algorithm>

long long solve(std::vector<long long> landStartTime, std::vector<long long> landDuration, std::vector<long long> waterStartTime, std::vector<long long> waterDuration) {
    long long min_time = 1e18;
    for (int i = 0; i < landStartTime.size(); ++i) {
        for (int j = 0; j < waterStartTime.size(); ++j) {
            // Scenario 1: Land first then water
            long long land_end = landStartTime[i] + landDuration[i];
            long long water_start = std::max(land_end, waterStartTime[j]);
            long long water_end = water_start + waterDuration[j];
            long long scenario1 = water_end;

            // Scenario 2: Water first then land
            long long water_end2 = waterStartTime[j] + waterDuration[j];
            long long land_start = std::max(water_end2, landStartTime[i]);
            long long land_end2 = land_start + landDuration[i];
            long long scenario2 = land_end2;

            long long current_min = std::min(scenario1, scenario2);
            if (current_min < min_time) {
                min_time = current_min;
            }
        }
    }
    return min_time;
}
